// Steampunk Airship — a Victorian sci-fi dirigible.
// A large elongated fabric envelope above a wooden gondola hull with brass
// portholes, brass tail fins/rudders, rigging struts, and twin propellers.
// Self-colored via api.label so the catalog thumbnail renders vibrant.
const { Manifold, CrossSection } = api;
api.material('brass'); // viewport shading preset only — no effect on headless previews

// ---------------------------------------------------------------------------
// Orientation: airship runs along +X (nose at +X, tail at -X). Z is up.
// Envelope centered high; gondola slung below it.
// ---------------------------------------------------------------------------

const ENV_LEN = 116;      // envelope length along X
const ENV_R = 23;         // envelope max radius
const ENV_Z = 46;         // envelope centerline height

// Shared radius-of-envelope-at-x helper (single source of truth)
function envR(x) {
  const t = (x + ENV_LEN / 2) / ENV_LEN;
  if (t <= 0 || t >= 1) return 0.01;
  const s = Math.sin(Math.PI * t);
  const noseBias = Math.pow(t, 0.65);
  return ENV_R * Math.pow(s, 0.62) * (0.55 + 0.45 * noseBias);
}

// ===========================================================================
// 1. ENVELOPE (the balloon) — surface of revolution from an airfoil-ish profile
// ===========================================================================
// Build a smooth teardrop/cigar profile: X = position along length (becomes
// height after revolve remap... we instead revolve a profile then orient).
// revolve() spins a CrossSection (X=radial, Y=height) around Y, remaps to Z-up.
// So we make a profile whose Y runs the LENGTH of the ship and X is the radius,
// then rotate the result to lie along X.
function envelopeProfile(halfLen, maxR) {
  const pts = [];
  const N = 40;
  // Start on the axis at the tail tip (r=0) so the revolved solid closes to a
  // true point there — leaving a tiny non-zero radius (e.g. 0.05) instead would
  // revolve into a hair-thin axis tube along z=ENV_Z, which later booleans
  // expose as a degenerate zero-volume sheet at the centerline.
  pts.push([0, -halfLen]);
  // nose at top (+Y), tail at bottom (-Y). Slightly fuller toward nose.
  // Interior stations only (skip i=0 and i=N — those are the axis tips above).
  for (let i = 1; i < N; i++) {
    const t = i / N;                 // 0..1 from tail to nose
    const y = (t - 0.5) * 2 * halfLen;
    // radius profile: fuller, blunt nose; long tapering tail.
    const s = Math.sin(Math.PI * t); // 0 at ends, 1 in middle
    const noseBias = Math.pow(t, 0.65);
    const tailBias = Math.pow(1 - t, 1.25);
    const r = maxR * Math.pow(s, 0.62) * (0.55 + 0.45 * noseBias) * (0.6 + 0.4 * (1 - tailBias * 0.0));
    pts.push([Math.max(0.05, r), y]);
  }
  // close on the axis at the nose tip (r=0); the polygon auto-closes back down
  // the axis from here to the tail-tip start point.
  pts.push([0, halfLen]);
  return CrossSection.ofPolygons([pts]);
}

let envelope = envelopeProfile(ENV_LEN / 2, ENV_R)
  .revolve()
  .rotate([0, 0, 0]);
// revolve gives a Z-up shape spun about Z with the profile's Y as Z.
// Rotate it so its long axis lies along X.
envelope = envelope.rotate([0, 90, 0]).translate([0, 0, ENV_Z]);

// Longitudinal seam ribs on the envelope (raised bands running nose->tail)
const ribs = [];
const ribCount = 7;
// Rivet stud: a squashed dome (flattened sphere), embedded radially into each
// rib ring so it bites into the brass band by well over 0.5u and pokes out as
// a small visible bump. Built once, reused (translated+rotated) per rib.
const rivetDome = Manifold.sphere(0.9, 12).scale([1, 0.6, 1]);
const rivets = [];
for (let i = 0; i < ribCount; i++) {
  const x = -ENV_LEN / 2 + 8 + (i * (ENV_LEN - 16)) / (ribCount - 1);
  const r = envR(x);
  if (r < 2) continue;
  const ring = Manifold.cylinder(1.6, r + 0.6, r + 0.6)
    .rotate([0, 90, 0])
    .translate([x - 0.8, 0, ENV_Z]);
  const innerCut = Manifold.cylinder(2.0, r - 0.4, r - 0.4)
    .rotate([0, 90, 0])
    .translate([x - 1.0, 0, ENV_Z]);
  ribs.push(ring.subtract(innerCut));
  // Row of rivets around this rib's ring: circularPattern about the rib's own
  // X-axis center, radius = rib outer surface (r+0.6) minus a 0.3u embed depth
  // so ~0.84u of each dome buries into the band while ~0.24u pokes proud.
  // Count scales with the ring's circumference so spacing stays even (dense
  // ribs amidships, sparser near the tapered nose/tail).
  const ringRadius = r + 0.3;
  const rivetCount = Math.max(6, Math.round((2 * Math.PI * ringRadius) / 4.5));
  // Position the dome in absolute world space at radius `ringRadius` from the
  // rib's own center [x-0.8, 0, ENV_Z] — circularPattern's `radius` shortcut
  // translates from the WORLD origin, not from a custom `center`, so with a
  // non-origin center it would push the ring wildly off-axis. Pre-place it
  // ourselves and let circularPattern only rotate about the correct center.
  const rivetAtStation = rivetDome.translate([x - 0.8, ringRadius, ENV_Z]);
  rivets.push(
    api.circularPattern(rivetAtStation, rivetCount, {
      axis: 'x',
      center: [x - 0.8, 0, ENV_Z],
    })
  );
}
const ribBands = Manifold.union(ribs);
const rivetStuds = Manifold.union(rivets);

// Nose cap / mooring cone (brass). The tip stays blunt (r≈1.4, not ~0) and the
// tip sphere overlaps it: a near-zero on-axis apex at z=ENV_Z unions into a
// degenerate coplanar sliver sheet, so keep the cone solid all the way out.
const noseCone = Manifold.cylinder(8, 4.5, 1.4, 24)
  .rotate([0, 90, 0])
  .translate([ENV_LEN / 2 - 2, 0, ENV_Z]);
const noseTip = Manifold.sphere(2.0).translate([ENV_LEN / 2 + 4.5, 0, ENV_Z]);
const noseAssembly = noseCone.add(noseTip);

// Tail finial (brass spike at the very back). Wide base (r=3) seats against the
// envelope tail (~x=-58) and overlaps it by >0.5u; spike points backward in -X.
// Keep the tip blunt (r≈1.2, not ~0) and cap it with an overlapping sphere — a
// near-zero on-axis apex at z=ENV_Z otherwise unions into a degenerate sliver.
const tailFinialCone = Manifold.cylinder(8, 3.0, 1.2, 24)
  .rotate([0, -90, 0])
  .translate([-ENV_LEN / 2 + 4, 0, ENV_Z]);
const tailFinialTip = Manifold.sphere(1.6).translate([-ENV_LEN / 2 - 3.0, 0, ENV_Z]);
const tailFinial = tailFinialCone.add(tailFinialTip);

// ===========================================================================
// 2. TAIL FINS & RUDDERS (brass) — cruciform fins at the tail
// ===========================================================================
// A single triangular fin profile in the XZ plane, extruded thin along its
// normal, then placed in 4 orientations around the tail axis.
function makeFin() {
  // fin profile in XY (will be oriented): chord along X, height along Y
  const prof = CrossSection.ofPolygons([
    [
      [0, 0],
      [30, 2],
      [27, 22],
      [8, 26],
      [0, 14],
    ],
  ]);
  let fin = prof.extrude(2.2, 0, 0, 1, true); // thin in Z, centered
  return fin;
}
const finBase = makeFin();
const finX = -ENV_LEN / 2 + 10; // tail region, overlapping envelope

// top fin
const finTop = finBase.translate([finX, 0, ENV_Z]);
// bottom fin (mirror)
const finBottom = finBase.mirror([0, 1, 0]).translate([finX, 0, ENV_Z]);
// left/right horizontal fins
const finRight = finBase.rotate([90, 0, 0]).translate([finX, 0, ENV_Z]);
const finLeft = finBase.rotate([90, 0, 0]).mirror([0, 1, 0]).translate([finX, 0, ENV_Z]);
const finsAssembly = finTop.add(finBottom).add(finRight).add(finLeft);

// Rudder posts / hinge cylinders where fins meet (decorative brass)
const hubRing = Manifold.cylinder(10, 5.5, 5.5, 24)
  .rotate([0, 90, 0])
  .translate([finX - 5, 0, ENV_Z]);
const hubInner = Manifold.cylinder(11, 4.2, 4.2, 24)
  .rotate([0, 90, 0])
  .translate([finX - 5.5, 0, ENV_Z]);
const tailHub = hubRing.subtract(hubInner);

// ===========================================================================
// 3. GONDOLA HULL (wood) — boat-like hull slung below the envelope
// ===========================================================================
const GON_Z = 0;          // gondola centerline height (slung well below envelope)
const GON_LEN = 74;
const GON_W = 19;
const GON_H = 15;

// Build hull as a lofted boat. Each station is a thin stacked-slab wedge; we
// hull CONSECUTIVE stations together so the loft is one continuous solid (a
// per-station union leaves ~8u gaps between 1.2u-thick wedges → disconnected
// slabs, which is what split the bow/stern off into floating components).
const HN = 9;
function hullStation(i) {
  const t = i / HN;
  const x = -GON_LEN / 2 + t * GON_LEN;
  // taper toward bow (+X) and stern (-X); bow more pointed
  const bow = Math.pow(t, 0.5);
  const stern = Math.pow(1 - t, 0.6);
  const widthScale = Math.sin(Math.PI * Math.min(1, t * 1.08)) * 0.5 + 0.55;
  const w = GON_W * Math.min(1, widthScale) * (0.35 + 0.65 * bow) * (0.5 + 0.5 * stern * 1.0 + 0.0);
  const ww = Math.max(2.5, w);
  // top deck slab (wide, flat)
  const top = Manifold.cube([1.2, ww, 0.1], true).translate([x, 0, GON_Z + GON_H / 2]);
  // mid slab
  const mid = Manifold.cube([1.2, ww * 0.92, 0.1], true).translate([x, 0, GON_Z]);
  // keel point (narrow, lower)
  const keelW = Math.max(0.8, ww * 0.16);
  const keel = Manifold.cube([1.2, keelW, 0.1], true).translate([x, 0, GON_Z - GON_H / 2]);
  return top.add(mid).add(keel);
}
const hullSlabs = [];
for (let i = 0; i < HN; i++) {
  // hull this station's slabs together with the next station's → a solid wedge
  // spanning the gap, so the full chain of wedges overlaps into one body.
  hullSlabs.push(hullStation(i).add(hullStation(i + 1)).hull());
}
let hull = Manifold.union(hullSlabs);

// Hollow the top of the hull into an open cockpit / cabin well, then re-close
// with a deck so it stays watertight but reads as a hull with bulwarks.
const bulwarkCut = Manifold.cube([GON_LEN - 12, GON_W - 5, 6], true)
  .translate([0, 0, GON_Z + GON_H / 2 - 1]);
hull = hull.subtract(bulwarkCut);
// Deck floor closing the bulwark well. The well's solid floor is at z≈3.5, so
// make the deck thick enough to dip below it (bottom ~z=2.8) and fuse into the
// solid hull rather than floating in the hollow.
const deck = Manifold.cube([GON_LEN - 14, GON_W - 6.5, 2.2], true)
  .translate([0, 0, GON_Z + GON_H / 2 - 3.6]);

// Hull plank lines (thin grooves) — subtract shallow bands along the sides
let plankCuts = [];
for (let k = 0; k < 3; k++) {
  const z = GON_Z - 2 - k * 3;
  const band = Manifold.cube([GON_LEN - 6, GON_W + 2, 0.35], true).translate([0, 0, z]);
  const inner = Manifold.cube([GON_LEN - 6, GON_W - 1.5, 1.0], true).translate([0, 0, z]);
  plankCuts.push(band.subtract(inner));
}
hull = hull.subtract(Manifold.union(plankCuts));

// Keel strip (darker wood) running along the bottom
const keelStrip = Manifold.cube([GON_LEN - 4, 1.4, 2.2], true)
  .translate([0, 0, GON_Z - GON_H / 2 + 0.5]);

// Gunwale rail / bulwark wall around the deck opening. Tall enough to bridge the
// deck floor (top ~z=5.0) up to the hull side walls so it fuses with both rather
// than floating as a thin trim ring above the bulwark cut.
const railOuter = Manifold.cube([GON_LEN - 11, GON_W - 4.2, 5.6], true)
  .translate([0, 0, GON_Z + GON_H / 2 - 2.0]);
const railInner = Manifold.cube([GON_LEN - 14, GON_W - 7.5, 4.4], true)
  .translate([0, 0, GON_Z + GON_H / 2 - 0.6]);
const rail = railOuter.subtract(railInner);

// ===========================================================================
// 4. PORTHOLES (brass rings + dark glass) along the hull sides
// ===========================================================================
const portRings = [];
const portGlass = [];
const portXs = [-22, -13, -4, 5, 14, 23];
// Hull side-wall half-width at the mid slab (z≈0, widest) for each station, so
// each porthole can be seated against the actual wall and bite into it by >0.5u.
function hullMidHalfW(x) {
  const slabs = [];
  for (let i = 0; i <= HN; i++) {
    const t = i / HN;
    const sx = -GON_LEN / 2 + t * GON_LEN;
    const bow = Math.pow(t, 0.5);
    const stern = Math.pow(1 - t, 0.6);
    const widthScale = Math.sin(Math.PI * Math.min(1, t * 1.08)) * 0.5 + 0.55;
    const w = GON_W * Math.min(1, widthScale) * (0.35 + 0.65 * bow) * (0.5 + 0.5 * stern);
    const ww = Math.max(2.5, w);
    slabs.push({ sx, hw: (ww * 0.92) / 2 });
  }
  for (let i = 0; i < slabs.length - 1; i++) {
    if (x >= slabs[i].sx && x <= slabs[i + 1].sx) {
      const f = (x - slabs[i].sx) / (slabs[i + 1].sx - slabs[i].sx);
      return slabs[i].hw * (1 - f) + slabs[i + 1].hw * f;
    }
  }
  return slabs[slabs.length - 1].hw;
}
for (const px of portXs) {
  const hw = hullMidHalfW(px);
  for (const sy of [-1, 1]) {
    // Seat the ring so its inner end sits ~2u inside the hull wall: ring spans
    // [y-3.2, y] along Y; place its outer face just proud of the wall.
    const yOuter = sy * (hw + 1.0); // ring outer face ~1u proud of the wall
    const ring = Manifold.cylinder(3.2, 2.4, 2.4, 24)
      .rotate([sy > 0 ? 90 : -90, 0, 0])
      .translate([px, yOuter, GON_Z + 0.5]);
    const ringInner = Manifold.cylinder(3.6, 1.6, 1.6, 24)
      .rotate([sy > 0 ? 90 : -90, 0, 0])
      .translate([px, yOuter, GON_Z + 0.5]);
    portRings.push(ring.subtract(ringInner));
    // glass sits just inside the ring, overlapping it
    const glass = Manifold.cylinder(1.6, 1.7, 1.7, 24)
      .rotate([sy > 0 ? 90 : -90, 0, 0])
      .translate([px, yOuter - sy * 0.6, GON_Z + 0.5]);
    portGlass.push(glass);
  }
}
const portholeRings = Manifold.union(portRings);
const portholeGlass = Manifold.union(portGlass);

// Cabin / wheelhouse on the deck (wood with a copper roof)
const cabin = Manifold.cube([20, GON_W - 8, 7], true)
  .translate([6, 0, GON_Z + GON_H / 2 + 2]);
// arched copper roof = half-cylinder
const roofArch = Manifold.cylinder(20, (GON_W - 8) / 2, (GON_W - 8) / 2, 32)
  .rotate([0, 90, 0])
  .translate([6 - 10, 0, GON_Z + GON_H / 2 + 5.5]);
const roofTrim = Manifold.cube([20.5, GON_W - 7, 1.0], true)
  .translate([6, 0, GON_Z + GON_H / 2 + 5.6]);

// Cabin front windows (dark glass)
const cabinWin = [];
for (const wy of [-3, 0, 3]) {
  cabinWin.push(
    Manifold.cube([0.8, 2.4, 3.4], true).translate([16.2, wy, GON_Z + GON_H / 2 + 2])
  );
}
const cabinWindows = Manifold.union(cabinWin);

// Smokestack / steam funnel (copper) rising from aft cabin
const stack = Manifold.cylinder(11, 1.8, 1.6, 24)
  .translate([-6, 0, GON_Z + GON_H / 2 + 1]);
const stackCap = Manifold.cylinder(1.6, 2.4, 2.4, 24)
  .translate([-6, 0, GON_Z + GON_H / 2 + 11]);
const smokestack = stack.add(stackCap);

// ===========================================================================
// 5. RIGGING / SUSPENSION STRUTS connecting gondola to envelope
// ===========================================================================
const struts = [];
function strut(x1, y1, z1, x2, y2, z2, r) {
  // a thin cylinder between two points, approximated via hull of two spheres
  const a = Manifold.sphere(r).translate([x1, y1, z1]);
  const b = Manifold.sphere(r).translate([x2, y2, z2]);
  return a.add(b).hull();
}
const strutXs = [-26, -10, 10, 26];
const deckZ = GON_Z + GON_H / 2;
// The bulwark cut hollows the deck well (z≈3.5..9.5 at |y|<7), so a strut at
// y=±5.5 only finds solid hull below z≈3.5. Route the strut bottoms all the way
// down to z≈-1 so they bite into the solid lower hull by well over 0.5u, while
// the strut tops still overlap the envelope skin.
const strutBottomZ = GON_Z - 1; // -1, solidly inside the lower hull
for (const sx of strutXs) {
  const r = envR(sx);
  const envBottomZ = ENV_Z - r + 1.5;
  // two angled struts (V) per station — overlap solid hull and envelope solidly
  struts.push(strut(sx, -5.5, strutBottomZ, sx, -2.5, envBottomZ, 0.7));
  struts.push(strut(sx, 5.5, strutBottomZ, sx, 2.5, envBottomZ, 0.7));
}
const rigging = Manifold.union(struts);

// Suspension cables along the length (thin longitudinal rods, brass)
const cableTop = strut(-30, 0, deckZ + 0.8, 30, 0, deckZ + 0.8, 0.4);

// ===========================================================================
// 6. PROPELLERS (twin) — brass hub + wooden blades, on side outriggers
// ===========================================================================
function makePropeller() {
  // hub (brass), spin axis = X
  const hub = Manifold.cylinder(3.6, 1.6, 1.6, 20).rotate([0, 90, 0]).translate([-1.8, 0, 0]);
  const hubCone = Manifold.cylinder(3.0, 1.6, 0.3, 20).rotate([0, 90, 0]).translate([1.8, 0, 0]);
  // Blade: tapered paddle. Profile lives in XY (X=axial chord, Y=radial length);
  // extruded thin in Z, then tilted (pitch) and stood up so it radiates in the
  // rotation plane perpendicular to the X spin axis.
  // Blade root starts well inside the hub radius (y=-1.0) so each blade buries
  // into the hub by >0.5u after stand-up, guaranteeing they fuse.
  const bladeProf = CrossSection.ofPolygons([
    [
      [-2.4, -1.0],
      [2.4, -1.0],
      [1.8, 11.0],
      [0, 13.0],
      [-1.8, 11.0],
    ],
  ]);
  // thin slab in Z; give it a pitch tilt about its radial (Y) axis, then
  // rotate the slab up so the radial direction points +Z (rotation plane = YZ).
  let blade = bladeProf
    .extrude(1.2, 0, 0, 1, true)
    .rotate([0, 20, 0])  // pitch
    .rotate([-90, 0, 0]); // stand radial axis up into +Z
  const blades = api.circularPattern(blade, 4, { axis: 'x' });
  return { hub: hub.add(hubCone), blades };
}

const prop = makePropeller();
const propSpots = [
  { y: GON_W / 2 + 5, z: GON_Z + 1 },
  { y: -(GON_W / 2 + 5), z: GON_Z + 1 },
];
const propHubs = [];
const propBlades = [];
const propMounts = [];
for (const sp of propSpots) {
  const px = -GON_LEN / 2 - 2; // aft of the gondola
  propHubs.push(prop.hub.translate([px, sp.y, sp.z]));
  propBlades.push(prop.blades.translate([px, sp.y, sp.z]));
  // outrigger mount arm from hull to prop (wood + brass collar). Start well
  // inboard where the hull is solid (x=-26, y=±3) and end deep inside the prop
  // hub (px+2) so the arm bridges hull→hub with >0.5u overlap at both ends.
  const arm = strut(-26, sp.y > 0 ? 3 : -3, sp.z, px + 2, sp.y, sp.z, 1.1);
  propMounts.push(arm);
}
const propellerHubs = Manifold.union(propHubs);
const propellerBlades = Manifold.union(propBlades);
const propellerArms = Manifold.union(propMounts);

// ===========================================================================
// 7. ASSEMBLE WITH SELF-COLORING LABELS
// ===========================================================================
const fabricShape = envelope;
const ribsBrass = ribBands.add(noseAssembly).add(tailFinial).add(tailHub).add(rivetStuds);
const finsBrass = finsAssembly;
const woodShape = hull.add(deck).add(rail).add(cabin).add(propellerArms);
const woodDark = keelStrip;
const copperShape = roofArch.add(roofTrim).add(smokestack);
const brassFittings = portholeRings.add(rigging).add(cableTop).add(propellerHubs);
const glassShape = portholeGlass.add(cabinWindows);
const propWood = propellerBlades;

return api.labeledUnion([
  { name: 'envelope_fabric', shape: fabricShape, color: '#b54a3a' },   // deep crimson airship silk
  { name: 'envelope_ribs', shape: ribsBrass, color: '#c08a2d' },       // brass ribs & nose cone
  { name: 'tail_fins', shape: finsBrass, color: '#cf9a35' },           // brass tail fins
  { name: 'gondola_wood', shape: woodShape, color: '#7a4a22' },        // varnished oak hull
  { name: 'keel', shape: woodDark, color: '#3d2410' },                 // dark keel strip
  { name: 'copper_roof', shape: copperShape, color: '#2e8b74' },       // verdigris copper roof & stack
  { name: 'brass_fittings', shape: brassFittings, color: '#d9a441' },  // portholes, rigging, prop hubs
  { name: 'glass', shape: glassShape, color: '#1c2a33' },              // dark porthole glass
  { name: 'prop_blades', shape: propWood, color: '#6b4326' },          // wooden propeller blades
]);
